import React, { useState, useEffect } from "react";
import axios from "axios";

function App() {
  const [text, setText] = useState("");
  const [output, setOutput] = useState({});
  const [mode, setMode] = useState("flipped");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!text) {
      setOutput({});
      return;
    }

    const timer = setTimeout(async () => {
      try {
        setLoading(true);

        const res = await axios.post(
          "http://localhost:5001/translate",
          { text }
        );

        setOutput(res.data);
      } catch (err) {
        console.error(err);
        setOutput({ error: "Backend error" });
      } finally {
        setLoading(false);
      }
    }, 300);

    return () => clearTimeout(timer);
  }, [text]);

  const getOutput = () => {
    if (loading) return "Translating...";
    if (!output) return "";

    switch (mode) {
      case "normal":
        return output.braille;
      case "flipped":
        return output.flippedBraille;
      case "mirror":
        return output.mirroredBraille;
      case "both":
        return output.flippedMirroredBraille;
      default:
        return "";
    }
  };

  return (
    <div style={styles.container}>
      <h1>Braille Translator</h1>

      <textarea
        placeholder="Enter text..."
        value={text}
        onChange={(e) => setText(e.target.value)}
        style={styles.textarea}
      />

      <div style={styles.buttons}>
        <button onClick={() => setMode("normal")}>Normal</button>
        <button onClick={() => setMode("flipped")}>Flipped</button>
        <button onClick={() => setMode("mirror")}>Mirror</button>
        <button onClick={() => setMode("both")}>Flipped + Mirror</button>
      </div>

      <textarea
        value={getOutput()}
        readOnly
        style={styles.textarea}
      />
    </div>
  );
}

const styles = {
  container: {
    maxWidth: "800px",
    margin: "40px auto",
    fontFamily: "Arial"
  },
  textarea: {
    width: "100%",
    height: "120px",
    marginTop: "20px",
    padding: "10px",
    fontSize: "16px"
  },
  buttons: {
    marginTop: "10px",
    display: "flex",
    gap: "10px"
  }
};

export default App;
